import InventoryToolPlaceholder from '../../components/InventoryToolPlaceholder'

export default async function AppPage() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  // You can pass user data down to your tool if needed
  // e.g., for scoping sessions to the logged-in user
  return (
    <div style={{ padding: '1.5rem', maxWidth: 1400, margin: '0 auto' }}>
      {/* Replace with: <InventoryTool userId={user?.id} /> */}
      <InventoryToolPlaceholder userId={user?.id ?? ''} />
    </div>
  )
}
